import React, { useMemo, useState } from 'react'

import { Dialog, ErrorMessage } from '@jbrowse/core/ui'
import { getSession } from '@jbrowse/core/util'
import {
  Button,
  Checkbox,
  DialogActions,
  DialogContent,
  FormControlLabel,
  MenuItem,
  TextField,
  Typography,
} from '@mui/material'

import ProgressDots from './ProgressDots'
import LocalBlastHelp from './LocalBlastHelp'

import { featuresFromBlastHits } from '../utils/blastFeatures'
import { featuresFromBlastNHits } from '../utils/blastNFeatures'
import {
  addBlastFeatureTrack,
  getAppendableBlastTracks,
  sanitizeTrackId,
} from '../utils/blastTrackConfig'
import { getFeatureName } from '../utils/featureSequence'
import {
  fetchLocalBlastDatabases,
  localBlastDatabaseValue,
  queryLocalBlastReports,
  selectedLocalBlastDatabase,
  type LocalBlastDatabase,
} from '../utils/localBlast'
import { queryBlast, queryBlastReports } from '../utils/ncbiBlast'
import { getProteinSequence } from '../utils/proteinFromCds'
import { queryGeneFeature } from '../utils/queryGeneFeatures'
import {
  fetchBlastableGenes,
  fetchRegionSequence,
  regionLabel,
} from '../utils/regionData'

import type { FromConfigFeature } from '../utils/blastTrackConfig'
import type { BlastQueryReport } from '../utils/ncbiBlast'
import type { SelectedRegion } from '../utils/regionData'
import type { Feature } from '@jbrowse/core/util'
import type { LinearGenomeViewModel } from '@jbrowse/plugin-linear-genome-view'

const proteinDatabaseOptions = ['nr', 'nr_cluster_seq'] as const
const proteinProgramOptions = ['blastp', 'quick-blastp'] as const
const defaultProteinDatabase = 'nr_cluster_seq'
const defaultProteinProgram = 'blastp'
const defaultBlastnHitLimit = 5
const defaultBatchHitLimit = 3
const defaultHspLimit = 1
const defaultMinIdentityPercent = 30
const defaultMaxRegionBp = 50_000
const highVolumeGeneWarningThreshold = 10
const ncbiBlastUrl = 'https://blast.ncbi.nlm.nih.gov/Blast.cgi'

export type SelectionBlastMode = 'blastn-region' | 'blastp-genes'

export default function BlastSelectionDialog({
  handleClose,
  mode,
  model,
  regions,
}: {
  handleClose: () => void
  mode: SelectionBlastMode
  model: LinearGenomeViewModel
  regions: SelectedRegion[]
}) {
  const appendBlastProgram = mode === 'blastn-region' ? 'blastn' : 'blastp'
  const appendAssemblyName = regions.length === 1 ? regions[0].assemblyName : ''
  const appendableBlastTracks = useMemo(
    () =>
      appendAssemblyName
        ? getAppendableBlastTracks({
            assemblyName: appendAssemblyName,
            blastProgram: appendBlastProgram,
            view: model,
          })
        : [],
    [appendAssemblyName, appendBlastProgram, model],
  )
  const [blastDatabase, setBlastDatabase] = useState<string>(
    mode === 'blastn-region' ? 'nt' : defaultProteinDatabase,
  )
  const [blastProgram, setBlastProgram] =
    useState<(typeof proteinProgramOptions)[number]>(defaultProteinProgram)
  const [hitLimit, setHitLimit] = useState(
    mode === 'blastn-region' ? defaultBlastnHitLimit : defaultBatchHitLimit,
  )
  const [hspLimit, setHspLimit] = useState(defaultHspLimit)
  const [localBlastDatabases, setLocalBlastDatabases] = useState<
    LocalBlastDatabase[]
  >([])
  const [precomputedBlastTableValue, setPrecomputedBlastTableValue] =
    useState('')
  const [loadingLocalDatabases, setLoadingLocalDatabases] = useState(false)
  const [localAllHits, setLocalAllHits] = useState(false)
  const [minIdentityPercent, setMinIdentityPercent] = useState(
    defaultMinIdentityPercent,
  )
  const [includeGenericDescriptions, setIncludeGenericDescriptions] =
    useState(true)
  const [highlightLongerSubjectProteins, setHighlightLongerSubjectProteins] =
    useState(true)
  const [showMismatchMarkers, setShowMismatchMarkers] = useState(false)
  const [maxRegionBp, setMaxRegionBp] = useState(defaultMaxRegionBp)
  const [progress, setProgress] = useState('')
  const [error, setError] = useState<unknown>()
  const [running, setRunning] = useState(false)
  const [appendToExistingTrack, setAppendToExistingTrack] = useState(false)
  const appendTargetTrack = appendableBlastTracks[0]
  const precomputedBlastTable = selectedLocalBlastDatabase({
    databases: localBlastDatabases,
    value: precomputedBlastTableValue,
  })

  const title =
    mode === 'blastn-region'
      ? 'BLASTN selected region'
      : 'BLASTP genes in selected region'
  const regionText =
    regions.length === 1
      ? regionLabel(regions[0])
      : `${regions.length} selected regions`

  async function runBlast() {
    try {
      setRunning(true)
      setError(undefined)
      if (mode === 'blastn-region') {
        await runBlastnRegion()
      } else {
        await runBlastpGenes('ncbi')
      }
      handleClose()
    } catch (e) {
      console.error(e)
      setError(e)
    } finally {
      setRunning(false)
    }
  }

  async function runPrecomputedBlastpGenes() {
    try {
      setRunning(true)
      setError(undefined)
      if (!precomputedBlastTable) {
        throw new Error('Choose a precomputed BLASTP table first.')
      }
      await runBlastpGenes('precomputed')
      handleClose()
    } catch (e) {
      console.error(e)
      setError(e)
    } finally {
      setRunning(false)
    }
  }

  async function loadLocalDatabases() {
    try {
      setLoadingLocalDatabases(true)
      setError(undefined)
      const databases = await fetchLocalBlastDatabases({
        program: 'blastp',
        onProgress: setProgress,
      })
      setLocalBlastDatabases(databases)
      if (!databases.length) {
        throw new Error(
          'No precomputed BLASTP tables are configured for BlastTrack.',
        )
      }
      setPrecomputedBlastTableValue(localBlastDatabaseValue(databases[0]))
      setProgress(`Loaded ${databases.length} precomputed BLASTP table(s).`)
    } catch (e) {
      console.error(e)
      setError(e)
    } finally {
      setLoadingLocalDatabases(false)
    }
  }

  async function runBlastnRegion() {
    const region = getSingleRegion(regions)
    const regionLength = region.end - region.start
    const sanitizedMaxRegionBp = sanitizeMaxRegionBp(maxRegionBp)
    if (regionLength > sanitizedMaxRegionBp) {
      throw new Error(
        `Selected region is ${regionLength.toLocaleString()} bp. Increase "Max region bp" to submit the whole region.`,
      )
    }

    setProgress(`Fetching sequence for ${regionLabel(region)}...`)
    const sequence = cleanNucleotideSequence(
      await fetchRegionSequence({ region, view: model }),
    )
    if (!sequence) {
      throw new Error(`No reference sequence was found for ${regionLabel(region)}`)
    }

    const sanitizedHitLimit = sanitizeHitLimit(hitLimit, defaultBlastnHitLimit)
    const sanitizedHspLimit = sanitizeHspLimit(hspLimit)
    const { hits, rid } = await queryBlast({
      query: fastaRecord(regionLabel(region), sequence),
      blastDatabase,
      blastProgram: 'blastn',
      hitLimit: sanitizedHitLimit,
      baseUrl: ncbiBlastUrl,
      onProgress: setProgress,
    })
    const features = featuresFromBlastNHits({
      hitLimit: sanitizedHitLimit,
      hspLimit: sanitizedHspLimit,
      hits,
      idPrefix: sanitizeTrackId(
        `region_${region.refName}_${region.start}_${rid}`,
      ),
      queryLength: sequence.length,
      region,
      showMismatchMarkers,
    })
    if (!features.length) {
      throw new Error('NCBI BLASTN completed, but no alignments were mapped')
    }

    addBlastFeatureTrack({
      appendToTrackId: appendToExistingTrack
        ? appendTargetTrack?.trackId
        : undefined,
      assemblyName: region.assemblyName,
      baseUrl: ncbiBlastUrl,
      blastProgram: 'blastn',
      features,
      name: `BLASTN hits - ${regionLabel(region)}`,
      rid,
      trackId: sanitizeTrackId(
        `blastn_${region.refName}_${region.start}_${region.end}_${rid}`,
      ),
      view: model,
    })
  }

  async function runBlastpGenes(source: 'ncbi' | 'precomputed') {
    const selectedPrecomputedTable =
      source === 'precomputed' ? precomputedBlastTable : undefined
    const region = getSingleRegion(regions)
    const sanitizedHitLimit = sanitizeHitLimit(hitLimit, defaultBatchHitLimit)
    const sanitizedHspLimit = sanitizeHspLimit(hspLimit)
    const sanitizedMinIdentityPercent =
      sanitizeMinIdentityPercent(minIdentityPercent)
    const displayedHitLimit =
      selectedPrecomputedTable && localAllHits
        ? Number.POSITIVE_INFINITY
        : sanitizedHitLimit
    const runPrefix = sanitizeTrackId(
      `run_${Date.now()}_${region.refName}_${region.start}`,
    )

    setProgress(`Finding genes in ${regionLabel(region)}...`)
    const genes = await fetchBlastableGenes({ region, view: model })
    if (!genes.length) {
      throw new Error(
        `No visible gene, mRNA, or transcript features found in ${regionLabel(region)}. Zoom in until the gene track is rendered, then run BLASTP genes in selection again.`,
      )
    }

    const selectedGenes = genes
    if (
      !selectedPrecomputedTable &&
      selectedGenes.length >= highVolumeGeneWarningThreshold
    ) {
      getSession(model).notify(
        `Submitting ${selectedGenes.length} genes as one multi-FASTA BLASTP request. NCBI may slow high-volume use; BlastTrack spaces new submissions by at least 10 seconds and polls RIDs once per minute.`,
        'warning',
      )
    }
    const queries: {
      feature: Feature
      header: string
      idPrefix: string
      name: string
      queryIds: string[]
      sequence: string
    }[] = []
    const noSequenceFeatures: FromConfigFeature[] = []

    for (const [index, feature] of selectedGenes.entries()) {
      const name = String(getFeatureName(feature))
      const idPrefix = sanitizeTrackId(`${runPrefix}_gene_${index + 1}_${name}`)
      setProgress(
        `Translating gene ${index + 1}/${selectedGenes.length}: ${name}`,
      )
      let sequence = ''
      try {
        sequence = cleanProteinSequence(
          (await getProteinSequence({ feature, view: model })) ?? '',
        )
      } catch (e) {
        noSequenceFeatures.push(
          queryGeneFeature({
            feature,
            hitCount: 0,
            idPrefix,
            status: 'no_sequence',
            statusDetail: `sequence fetch failed: ${errorMessage(e)}`,
          }),
        )
        continue
      }
      if (sequence) {
        queries.push({
          feature,
          header: sanitizeFastaHeader(`gene_${index + 1}_${name}`),
          idPrefix,
          name,
          queryIds: precomputedBlastQueryIds(feature, name),
          sequence,
        })
      } else {
        noSequenceFeatures.push(
          queryGeneFeature({
            feature,
            hitCount: 0,
            idPrefix,
            status: 'no_sequence',
          }),
        )
      }
    }

    if (!queries.length) {
      addBlastFeatureTrack({
        appendToTrackId: appendToExistingTrack
          ? appendTargetTrack?.trackId
          : undefined,
        assemblyName: region.assemblyName,
        blastProgram: 'blastp',
        features: noSequenceFeatures,
        name: `BLASTP gene hits - ${regionLabel(region)}`,
        trackId: sanitizeTrackId(
          `blastp_genes_no_sequence_${region.refName}_${region.start}_${region.end}_${Date.now()}`,
        ),
        view: model,
      })
      getSession(model).notify(
        'Genes were found, but none had extractable CDS/protein sequence for BLASTP. Query markers were added to the BLAST track.',
        'warning',
      )
      return
    }

    const query = queries
      .map(({ header, sequence }) => fastaRecord(header, sequence))
      .join('\n')
    const { reports, rid } = selectedPrecomputedTable
      ? await queryLocalBlastReports({
          allHits: localAllHits,
          query,
          queryIds: queries.flatMap(({ queryIds }) => queryIds),
          blastDatabase: selectedPrecomputedTable,
          blastProgram: 'blastp',
          hitLimit: sanitizedHitLimit,
          hspLimit: sanitizedHspLimit,
          onProgress: message => {
            setProgress(`Precomputed BLASTP ${queries.length} genes: ${message}`)
          },
        })
      : await queryBlastReports({
          query,
          blastDatabase,
          blastProgram,
          hitLimit: sanitizedHitLimit,
          baseUrl: ncbiBlastUrl,
          onProgress: message => {
            setProgress(`BLASTP ${queries.length} genes: ${message}`)
          },
        })

    const resultBlastProgram = selectedPrecomputedTable ? 'blastp' : blastProgram
    const resultSource = selectedPrecomputedTable
      ? 'Precomputed BLASTP'
      : blastProgram === 'quick-blastp'
        ? 'NCBI quick-blastp'
        : 'NCBI BLASTP'
    const hitFeaturesByGene = new Map<Feature, FromConfigFeature[]>()
    const reportMatchesByGene = new Map<Feature, QueryReportMatch>()
    const hitFeatures = queries.flatMap(({ feature, header, idPrefix, queryIds, sequence }, index) => {
      const reportMatch = reportForQuery({
        candidateIds: [header, ...queryIds],
        fallbackIndex: index,
        header,
        queryCount: queries.length,
        reports,
      })
      reportMatchesByGene.set(feature, reportMatch)
      const renderedHits = featuresFromBlastHits({
        blastProgram: resultBlastProgram,
        highlightLongerSubjectProteins,
        hitLimit: displayedHitLimit,
        hspLimit: sanitizedHspLimit,
        hits: reportMatch.report?.hits ?? [],
        includeGenericDescriptions,
        idPrefix,
        minIdentityPercent: sanitizedMinIdentityPercent,
        queryFeature: feature,
        queryProteinLength: sequence.length,
        showMismatchMarkers,
        source: resultSource,
      })
      hitFeaturesByGene.set(feature, renderedHits)
      return renderedHits
    }) as FromConfigFeature[]

    const queryStatusFeatures = queries.flatMap(({ feature, idPrefix }) => {
      const renderedHits = hitFeaturesByGene.get(feature) ?? []
      const reportMatch = reportMatchesByGene.get(feature)
      if (renderedHits.length) {
        return []
      }
      if (reportMatch?.report) {
        return []
      }
      return [
        queryGeneFeature({
          feature,
          hitCount: 0,
          idPrefix,
          reportMatchedBy: reportMatch?.matchedBy,
          reportQueryId: reportMatch?.report?.queryId,
          reportQueryTitle: reportMatch?.report?.queryTitle,
          status: 'no_report',
        }),
      ]
    })
    const features = [
      ...queryStatusFeatures,
      ...noSequenceFeatures,
      ...hitFeatures,
    ]
    if (!hitFeatures.length) {
      throw new Error(
        `No BLASTP hits passed the current filters. Try lowering minimum identity below ${sanitizedMinIdentityPercent}% or including hypothetical/uncharacterized hits.`,
      )
    }

    addBlastFeatureTrack({
      appendToTrackId: appendToExistingTrack
        ? appendTargetTrack?.trackId
        : undefined,
      assemblyName: region.assemblyName,
      baseUrl: selectedPrecomputedTable ? undefined : ncbiBlastUrl,
      blastProgram: 'blastp',
      features,
      name: selectedPrecomputedTable
        ? `Precomputed BLASTP gene hits - ${regionLabel(region)}`
        : `BLASTP gene hits - ${regionLabel(region)}`,
      rid,
      trackId: sanitizeTrackId(
        `blastp_genes_${region.refName}_${region.start}_${region.end}_${rid}`,
      ),
      view: model,
    })

    const skippedNoSequence = selectedGenes.length - queries.length
    const submittedWithoutHits = queryStatusFeatures.filter(
      feature => feature.blastStatus === 'no_hits',
    ).length
    const submittedWithoutMatchedReport = queryStatusFeatures.filter(
      feature => feature.blastStatus === 'no_report',
    ).length
    if (
      skippedNoSequence ||
      submittedWithoutHits ||
      submittedWithoutMatchedReport
    ) {
      getSession(model).notify(
        [
          skippedNoSequence
            ? `${skippedNoSequence} genes marked without CDS/protein sequence`
            : '',
          submittedWithoutHits
            ? `${submittedWithoutHits} submitted genes had no BLAST hits`
            : '',
          submittedWithoutMatchedReport
            ? `${submittedWithoutMatchedReport} submitted genes could not be matched to an NCBI report`
            : '',
        ]
          .filter(Boolean)
          .join('; '),
        'warning',
      )
    }
  }

  return (
    <Dialog maxWidth="lg" title={title} open onClose={handleClose}>
      <DialogContent sx={{ width: '48rem', maxWidth: '90vw' }}>
        {error ? <ErrorMessage error={error} /> : null}
        {mode === 'blastp-genes' ? (
          <>
            <TextField
              margin="normal"
              select
              label="BLAST database"
              value={blastDatabase}
              onChange={event => {
                const nextDatabase = event.target.value
                setBlastDatabase(nextDatabase)
                if (nextDatabase === 'nr_cluster_seq') {
                  setBlastProgram('blastp')
                }
              }}
              sx={{ mr: 2, minWidth: 180 }}
            >
              {proteinDatabaseOptions.map(option => (
                <MenuItem key={option} value={option}>
                  {option}
                </MenuItem>
              ))}
            </TextField>
            <TextField
              margin="normal"
              select
              label="BLAST program"
              value={blastProgram}
              disabled={blastDatabase === 'nr_cluster_seq'}
              onChange={event => {
                setBlastProgram(
                  event.target.value as (typeof proteinProgramOptions)[number],
                )
              }}
              sx={{ minWidth: 180 }}
            >
              {proteinProgramOptions.map(option => (
                <MenuItem key={option} value={option}>
                  {option === 'quick-blastp'
                    ? 'quick-blastp (faster NCBI protein BLAST)'
                    : 'blastp (standard, slower)'}
                </MenuItem>
              ))}
            </TextField>
          </>
        ) : (
          <>
            <TextField
              margin="normal"
              label="BLAST database"
              value={blastDatabase}
              onChange={event => {
                setBlastDatabase(event.target.value)
              }}
              sx={{ mr: 2, minWidth: 180 }}
            />
            <TextField
              margin="normal"
              type="number"
              label="Max region bp"
              value={maxRegionBp}
              onChange={event => {
                setMaxRegionBp(Number(event.target.value))
              }}
              sx={{ width: 150 }}
            />
          </>
        )}
        <TextField
          disabled={Boolean(
            mode === 'blastp-genes' && precomputedBlastTable && localAllHits,
          )}
          margin="normal"
          type="number"
          label={mode === 'blastp-genes' ? 'Hits per gene' : 'Hits'}
          helperText={
            mode === 'blastp-genes'
              ? 'BLAST subject hits per query gene'
              : 'BLAST subject hits for this region'
          }
          value={hitLimit}
          onChange={event => {
            setHitLimit(Number(event.target.value))
          }}
          sx={{ ml: 2, width: mode === 'blastp-genes' ? 190 : 180 }}
        />
        {mode === 'blastp-genes' ? (
          <TextField
            margin="normal"
            type="number"
            label="Minimum identity (%)"
            helperText="Weighted across each BLASTP hit before rendering"
            value={minIdentityPercent}
            onChange={event => {
              setMinIdentityPercent(Number(event.target.value))
            }}
            sx={{ ml: 2, width: 210 }}
          />
        ) : null}
        <TextField
          margin="normal"
          type="number"
          label="Alignment segments"
          helperText="1 = best segment, most sensitive; 3 = looser and may draw less accurate segments"
          value={hspLimit}
          onChange={event => {
            setHspLimit(Number(event.target.value))
          }}
          sx={{ ml: 2, width: 210 }}
        />
        {mode === 'blastp-genes' ? (
          <>
            <FormControlLabel
              control={
                <Checkbox
                  checked={includeGenericDescriptions}
                  onChange={event => {
                    setIncludeGenericDescriptions(event.target.checked)
                  }}
                />
              }
              label="Include hypothetical/uncharacterized hits"
            />
            <FormControlLabel
              control={
                <Checkbox
                  checked={highlightLongerSubjectProteins}
                  onChange={event => {
                    setHighlightLongerSubjectProteins(event.target.checked)
                  }}
                />
              }
              label="Highlight larger subject proteins"
            />
          </>
        ) : null}
        <FormControlLabel
          control={
            <Checkbox
              checked={showMismatchMarkers}
              onChange={event => {
                setShowMismatchMarkers(event.target.checked)
              }}
            />
          }
          label="Show mismatch/gap ticks"
        />
        {appendTargetTrack ? (
          <FormControlLabel
            control={
              <Checkbox
                checked={appendToExistingTrack}
                onChange={event => {
                  setAppendToExistingTrack(event.target.checked)
                }}
              />
            }
            label={`Append to existing ${appendBlastProgram.toUpperCase()} track (experimental): ${
              appendTargetTrack.name
            }`}
          />
        ) : null}
        <Typography sx={{ mt: 2 }} variant="body2">
          Selection: {regionText}
        </Typography>
        <Typography sx={{ mt: 1 }} variant="body2">
          {mode === 'blastp-genes'
            ? 'A single multi-FASTA BLASTP request will be submitted for the selected genes, using the longest detected isoform per gene. Hits are drawn over each query gene CDS.'
            : 'The selected reference sequence will be submitted to blastn. HSPs are drawn over the selected genomic span.'}
        </Typography>
        <Typography sx={{ mt: 1 }} variant="body2">
          Mismatch and gap counts are kept in feature details. Red mismatch and
          yellow gap ticks are optional because dense alignments can be
          difficult to read.
        </Typography>
        <Typography sx={{ mt: 1 }} variant="body2">
          BlastTrack batches selected genes into one multi-FASTA request, spaces
          NCBI submissions at least 10 seconds apart, and polls each RID every
          30 seconds after the first check.
        </Typography>
        {mode === 'blastp-genes' ? (
          <>
            <Typography sx={{ mt: 3 }} variant="subtitle2">
              Precomputed BLASTP table
            </Typography>
            <Button
              disabled={running || loadingLocalDatabases}
              onClick={() => {
                void loadLocalDatabases()
              }}
              sx={{ mt: 1, mr: 1 }}
              variant="outlined"
            >
              Load tables
            </Button>
            <LocalBlastHelp />
            {localBlastDatabases.length ? (
              <TextField
                margin="normal"
                select
                label="Precomputed table"
                value={precomputedBlastTableValue}
                onChange={event => {
                  setPrecomputedBlastTableValue(event.target.value)
                }}
                sx={{ ml: 2, minWidth: 260 }}
              >
                {localBlastDatabases.map(database => (
                  <MenuItem
                    key={database.id}
                    value={localBlastDatabaseValue(database)}
                  >
                    {database.title ?? database.name}
                  </MenuItem>
                ))}
              </TextField>
            ) : null}
            {precomputedBlastTable ? (
              <FormControlLabel
                control={
                  <Checkbox
                    checked={localAllHits}
                    onChange={event => {
                      setLocalAllHits(event.target.checked)
                    }}
                  />
                }
                label="All precomputed BLAST hits"
              />
            ) : null}
            <Typography sx={{ mt: 1 }} variant="body2">
              Precomputed tables read static tabix-indexed BLASTP rows by
              selected query IDs; they do not submit a BLAST job.
            </Typography>
          </>
        ) : null}
        {running ? (
          <ProgressDots message={progress} />
        ) : null}
      </DialogContent>
      <DialogActions>
        <Button
          disabled={running}
          onClick={() => {
            void runBlast()
          }}
          variant="contained"
        >
          {mode === 'blastp-genes' ? 'Submit NCBI BLAST' : 'Submit'}
        </Button>
        {mode === 'blastp-genes' ? (
          <Button
            disabled={running || !precomputedBlastTable}
            onClick={() => {
              void runPrecomputedBlastpGenes()
            }}
            variant="outlined"
          >
            Load Precomputed Hits
          </Button>
        ) : null}
        <Button disabled={running} onClick={handleClose}>
          Cancel
        </Button>
      </DialogActions>
    </Dialog>
  )
}

function getSingleRegion(regions: SelectedRegion[]) {
  if (regions.length !== 1) {
    throw new Error(
      `BLAST currently supports one continuous selected region; this selection contains ${regions.length}.`,
    )
  }
  const region = regions[0]
  if (region.end <= region.start) {
    throw new Error('Selected region has no length')
  }
  return region
}

function sanitizeHitLimit(value: number, fallback: number) {
  if (!Number.isFinite(value)) {
    return fallback
  }
  return Math.min(100, Math.max(1, Math.floor(value)))
}

function sanitizeHspLimit(value: number) {
  if (!Number.isFinite(value)) {
    return defaultHspLimit
  }
  return Math.min(100, Math.max(1, Math.floor(value)))
}

function sanitizeMinIdentityPercent(value: number) {
  if (!Number.isFinite(value)) {
    return defaultMinIdentityPercent
  }
  return Math.min(100, Math.max(0, Number(value)))
}

function sanitizeMaxRegionBp(value: number) {
  if (!Number.isFinite(value)) {
    return defaultMaxRegionBp
  }
  return Math.min(1_000_000, Math.max(1, Math.floor(value)))
}

function cleanProteinSequence(sequence: string) {
  return sequence.replaceAll(/[^A-Za-z*]/g, '').toUpperCase()
}

function cleanNucleotideSequence(sequence: string) {
  return sequence.replaceAll(/[^A-Za-z]/g, '').toUpperCase()
}

function fastaRecord(header: string, sequence: string) {
  return `>${sanitizeFastaHeader(header)}\n${wrapSequence(sequence)}`
}

function sanitizeFastaHeader(header: string) {
  return sanitizeTrackId(header).slice(0, 120) || 'query'
}

interface QueryReportMatch {
  matchedBy?: 'query_id' | 'query_title' | 'response_order'
  report?: BlastQueryReport
}

function reportForQuery({
  candidateIds,
  fallbackIndex,
  header,
  queryCount,
  reports,
}: {
  candidateIds?: string[]
  fallbackIndex: number
  header: string
  queryCount: number
  reports: BlastQueryReport[]
}): QueryReportMatch {
  const normalizedIds = (candidateIds ?? [header])
    .map(normalizeReportId)
    .filter(Boolean)
  const queryIdMatch = reports.find(
    report =>
      Boolean(
        normalizeReportId(report.queryId) &&
          normalizedIds.includes(normalizeReportId(report.queryId)),
      ),
  )
  if (queryIdMatch) {
    return { matchedBy: 'query_id', report: queryIdMatch }
  }

  const queryTitleMatch = reports.find(report => {
    const normalizedTitle = normalizeReportId(report.queryTitle)
    if (!normalizedTitle) {
      return false
    }
    return normalizedIds.some(
      normalizedId =>
        normalizedTitle === normalizedId ||
        normalizedTitle.startsWith(`${normalizedId}_`) ||
        normalizedTitle.includes(`_${normalizedId}_`),
    )
  })
  if (queryTitleMatch) {
    return { matchedBy: 'query_title', report: queryTitleMatch }
  }

  if (reports.length === queryCount) {
    return { matchedBy: 'response_order', report: reports[fallbackIndex] }
  }

  return {}
}

function normalizeReportId(value?: string) {
  return value?.replaceAll(/[^A-Za-z0-9]+/g, '_').replaceAll(/^_+|_+$/g, '')
}

interface QueryIdFeatureJson {
  end?: number
  gene_id?: unknown
  id?: unknown
  name?: unknown
  parent?: unknown
  Parent?: unknown
  protein_id?: unknown
  start?: number
  subfeatures?: QueryIdFeatureJson[]
  transcript_id?: unknown
  type?: string
}

function precomputedBlastQueryIds(feature: Feature, featureName: string) {
  const json = feature.toJSON() as QueryIdFeatureJson
  const bestTranscript = bestTranscriptFeature(json)
  return uniqueStrings(
    uniqueStrings([
      ...idsFromFeatureJson(bestTranscript),
      ...idsFromFeatureJson(json),
      stringValue(featureName),
      stringValue(feature.id()),
      stringValue(feature.get('id')),
      stringValue(feature.get('name')),
      stringValue(feature.get('gene_id')),
      stringValue(feature.get('transcript_id')),
      ...idsFromFeatureJson(...(json.subfeatures ?? [])),
    ]).flatMap(id => idAliases(id)),
  )
}

function bestTranscriptFeature(feature: QueryIdFeatureJson) {
  const candidates = transcriptCandidates(feature)
  return candidates.sort((a, b) => cdsLength(b) - cdsLength(a))[0]
}

function transcriptCandidates(feature: QueryIdFeatureJson): QueryIdFeatureJson[] {
  const subfeatures = feature.subfeatures ?? []
  return [
    ...(feature.type === 'mRNA' || feature.type === 'transcript'
      ? [feature]
      : []),
    ...subfeatures.flatMap(transcriptCandidates),
  ]
}

function cdsLength(feature: QueryIdFeatureJson) {
  return collectCds(feature).reduce(
    (total, cds) => total + Math.max(0, (cds.end ?? 0) - (cds.start ?? 0)),
    0,
  )
}

function collectCds(feature: QueryIdFeatureJson): QueryIdFeatureJson[] {
  return [
    ...(feature.type === 'CDS' ? [feature] : []),
    ...(feature.subfeatures ?? []).flatMap(collectCds),
  ]
}

function idsFromFeatureJson(...features: (QueryIdFeatureJson | undefined)[]) {
  return features.flatMap(feature =>
    feature
      ? [
          stringValue(feature.id),
          stringValue(feature.name),
          stringValue(feature.gene_id),
          stringValue(feature.transcript_id),
          stringValue(feature.protein_id),
          stringValue(feature.Parent),
          stringValue(feature.parent),
        ]
      : [],
  )
}

function idAliases(id: string) {
  const trimmed = id.trim()
  const firstToken = trimmed.split(/\s+/)[0]
  const withoutPrefix = firstToken.replace(
    /^(rna|transcript|mrna|cds|protein)[:-]/i,
    '',
  )
  return uniqueStrings([
    trimmed,
    firstToken,
    withoutPrefix,
    withoutPrefix.replace(/\.(?:p|protein)\d*$/i, ''),
    withoutPrefix.replace(/\.prot$/i, ''),
  ])
}

function stringValue(value: unknown) {
  const first = Array.isArray(value) ? value[0] : value
  return typeof first === 'string' || typeof first === 'number'
    ? String(first)
    : ''
}

function uniqueStrings(values: string[]) {
  return [...new Set(values.map(value => value.trim()).filter(Boolean))]
}

function wrapSequence(sequence: string) {
  return sequence.match(/.{1,60}/g)?.join('\n') ?? sequence
}

function errorMessage(error: unknown) {
  return error instanceof Error ? error.message : String(error)
}
